const body = $input.first().json.body;

if (!body.rfpText) {
  return [{json:{
    error: true,
    message: 'rfpText field is required'
  }}];
}

return [{json:{
  rfpTitle:  body.rfpTitle  || 'Untitled RFP',
  rfpText:   body.rfpText,
  receivedAt: new Date().toISOString(),
  source:    body.source || 'webhook',
  error:     false
}}];

const aiResponse = $input.first().json.output ||
                   $input.first().json.text   ||
                   $input.first().json.message || '';

const cleaned = aiResponse
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  return [{json:{
    error: true,
    message: 'AI did not return valid JSON: ' + aiResponse.substring(0,200)
  }}];
}

return [{json:{
  ...parsed,
  parsedAt: new Date().toISOString()
}}];

